module branch_predictor(  
    input clk,  
    input reset,  
    input taken,  
    output reg prediction  
);  
    reg [0:0] obf_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            obf_counter <= 1'b0;  
        else begin  
            if (taken)  
                obf_counter <= (obf_counter == 1'b1) ? 1'b1 : obf_counter + 1'b1;  
            else  
                obf_counter <= (obf_counter == 1'b0) ? 1'b0 : obf_counter - 1'b1;  
        end  
    end  

    always @(*) begin  
        prediction = obf_counter;  
    end  
endmodule
